/**
 * Get the additional translation table for a language.
 * en/hn/hi are returned in their respective scripts.
 * All other 21 languages fall back to English (so Hinglish never leaks).
 */
export function getTM(lang: UILang): MoreT {
  switch (lang) {
    case "hn": return { ...EN, ...HN };
    case "hi": return { ...EN, ...HI };
    case "bn": return { ...EN, ...BN };
    case "mr": return { ...EN, ...MR };
    case "ta": return { ...EN, ...TA };
    case "te": return { ...EN, ...TE };
    case "gu": return { ...EN, ...GU };
    case "kn": return { ...EN, ...KN };
    case "ml": return { ...EN, ...ML };
    case "pa": return { ...EN, ...PA };
    case "or": return { ...EN, ...OR };
    case "as": return { ...EN, ...AS };
    case "zh": return { ...EN, ...ZH };
    case "es": return { ...EN, ...ES };
    case "ar": return { ...EN, ...AR };
    case "fr": return { ...EN, ...FR };
    case "pt": return { ...EN, ...PT };
    case "de": return { ...EN, ...DE };
    case "ru": return { ...EN, ...RU };
    case "ja": return { ...EN, ...JA };
    case "id": return { ...EN, ...ID };
    case "ko": return { ...EN, ...KO };
    case "tr": return { ...EN, ...TR };
    default:   return EN;
  }
}
